import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './Dashboard.css';

const API_URL = 'http://localhost:9000';

const Dashboard = ({ token }) => {
    const [portfolio, setPortfolio] = useState([]);
    const [symbol, setSymbol] = useState('');
    const [quantity, setQuantity] = useState('');
    const [error, setError] = useState('');
    const [message, setMessage] = useState('');

    useEffect(() => {
        fetchPortfolio();
    }, []);

    const fetchPortfolio = async () => {
        try {
            const response = await axios.get(`${API_URL}/portfolio/testuser`);
            setPortfolio(response.data);
        } catch (error) {
            setError('Erreur lors du chargement du portefeuille.');
        }
    };

    const handleAddAsset = async (e) => {
        e.preventDefault();
        if (!symbol || !quantity) {
            setError('Veuillez remplir tous les champs.');
            return;
        }
        try {
            await axios.post(`${API_URL}/portfolio/add`, { userId: 'testuser', symbol, quantity: parseInt(quantity) });
            setMessage('Action ajoutée avec succès !');
            setSymbol('');
            setQuantity('');
            fetchPortfolio();
        } catch (error) {
            setError('Erreur lors de l\'ajout de l\'action.');
        }
    };

    const handleRemoveAsset = async (e) => {
        e.preventDefault();
        if (!symbol || !quantity) {
            setError('Veuillez remplir tous les champs.');
            return;
        }
        try {
            await axios.post(`${API_URL}/portfolio/remove`, { userId: 'testuser', symbol, quantity: parseInt(quantity) });
            setMessage('Action vendue avec succès !');
            setSymbol('');
            setQuantity('');
            fetchPortfolio();
        } catch (error) {
            setError('Erreur lors de la vente de l\'action.');
        }
    };

    return (
        <div className="dashboard-container">
            <h2>📊 Mon Portefeuille</h2>
            {error && <p className="error">{error}</p>}
            {message && <p className="message">{message}</p>}

            <table>
                <thead>
                <tr>
                    <th>Symbole</th>
                    <th>Quantité</th>
                </tr>
                </thead>
                <tbody>
                {portfolio.length > 0 ? (
                    portfolio.map((asset, index) => (
                        <tr key={index}>
                            <td>{asset.symbol}</td>
                            <td>{asset.quantity}</td>
                        </tr>
                    ))
                ) : (
                    <tr>
                        <td colSpan="2">Aucune action dans le portefeuille.</td>
                    </tr>
                )}
                </tbody>
            </table>

            <div className="transaction-form">
                <h3>➕ Ajouter une action</h3>
                <form onSubmit={handleAddAsset}>
                    <input type="text" placeholder="Symbole (ex: AAPL)" value={symbol} onChange={(e) => setSymbol(e.target.value)} required />
                    <input type="number" placeholder="Quantité" value={quantity} onChange={(e) => setQuantity(e.target.value)} required />
                    <button type="submit">Acheter</button>
                </form>
            </div>

            <div className="transaction-form">
                <h3>➖ Vendre une action</h3>
                <form onSubmit={handleRemoveAsset}>
                    <input type="text" placeholder="Symbole (ex: AAPL)" value={symbol} onChange={(e) => setSymbol(e.target.value)} required />
                    <input type="number" placeholder="Quantité" value={quantity} onChange={(e) => setQuantity(e.target.value)} required />
                    <button type="submit">Vendre</button>
                </form>
            </div>
        </div>
    );
};

export default Dashboard;
